function solve(events) {
    let score = 0;
    let counter = 0;
    const N = events.length;

    for (let i = 0; i < N; i++) {
        const event = events[i];

        if (event === "0" || event === "1" || event === "2" || event === "3" || event === "4" || event === "6") {
            // Digit event
            score += parseInt(event);
        } else if (event === "W") {
            counter += 1;
            // Check stopping condition after updating counter
            if (counter === 10) {
                break;
            }
        } else if (event === "WD") {
            score += 1;
        } else if (event === "NB") {
            score += 1;
        }
    }

    return [score, counter];
}
